arguments.prompt:
You are building a veterinary clinic management Blazor Web App. The project is already scaffolded at `/tmp/sv-853694e2a8f1424186ac75de4d52b6b6/VetClinic` with:
- Interactive Server, Global interactivity (via `PageRenderMode` in App.razor)
- Individual authentication (ASP.NET Core Identity with SQLite)
- EF Core with SQLite

Your job is to implement the full application. Here's what needs to be done:

## 1. Domain Models

Create `/tmp/sv-853694e2a8f1424186ac75de4d52b6b6/VetClinic/Data/Models.cs` with these entities:

```csharp
namespace VetClinic.Data;

public class Owner
{
    public int Id { get; set; }
    public string FirstName { get; set; } = string.Empty;
    public string LastName { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public List<Pet> Pets { get; set; } = new();
}

public class Pet
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Species { get; set; } = string.Empty;
    public string Breed { get; set; } = string.Empty;
    public DateOnly DateOfBirth { get; set; }
    public decimal Weight { get; set; }
    public int OwnerId { get; set; }
    public Owner Owner { get; set; } = null!;
    public List<TreatmentNote> TreatmentNotes { get; set; } = new();
    public List<Appointment> Appointments { get; set; } = new();
}

public class TreatmentNote
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime Date { get; set; }
    public string Diagnosis { get; set; } = string.Empty;
    public string Treatment { get; set; } = string.Empty;
    public string Medications { get; set; } = string.Empty;
    public string Notes { get; set; } = string.Empty;
    public string VeterinarianName { get; set; } = string.Empty;
}

public class Appointment
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime StartTime { get; set; }
    public DateTime EndTime { get; set; }
    public string Reason { get; set; } = string.Empty;
    public AppointmentStatus Status { get; set; }
    public string VeterinarianName { get; set; } = string.Empty;
    public string Notes { get; set; } = string.Empty;
}

public enum AppointmentStatus
{
    Scheduled,
    Completed,
    Cancelled,
    NoShow
}

public class Invoice
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public int? AppointmentId { get; set; }
    public Appointment? Appointment { get; set; }
    public DateTime IssuedDate { get; set; }
    public DateTime? DueDate { get; set; }
    public List<InvoiceLineItem> LineItems { get; set; } = new();
    public decimal Total => LineItems.Sum(li => li.Amount);
    public InvoiceStatus Status { get; set; }
}

public enum InvoiceStatus
{
    Draft,
    Issued,
    Paid,
    Overdue,
    Cancelled
}

public class InvoiceLineItem
{
    public int Id { get; set; }
    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;
    public string Description { get; set; } = string.Empty;
    public decimal Amount { get; set; }
    public int Quantity { get; set; } = 1;
}

public class Payment
{
    public int Id { get; set; }
    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;
    public decimal Amount { get; set; }
    public DateTime PaymentDate { get; set; }
    public string Method { get; set; } = string.Empty; // Cash, Card, Check
    public string? Reference { get; set; }
}
```

## 2. Update ApplicationDbContext

Edit `/tmp/sv-853694e2a8f1424186ac75de4d52b6b6/VetClinic/Data/ApplicationDbContext.cs` to add DbSets and configure relationships:

```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace VetClinic.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Owner> Owners => Set<Owner>();
    public DbSet<Pet> Pets => Set<Pet>();
    public DbSet<TreatmentNote> TreatmentNotes => Set<TreatmentNote>();
    public DbSet<Appointment> Appointments => Set<Appointment>();
    public DbSet<Invoice> Invoices => Set<Invoice>();
    public DbSet<InvoiceLineItem> InvoiceLineItems => Set<InvoiceLineItem>();
    public DbSet<Payment> Payments => Set<Payment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Pet>()
            .HasOne(p => p.Owner)
            .WithMany(o => o.Pets)
            .HasForeignKey(p => p.OwnerId);

        builder.Entity<TreatmentNote>()
            .HasOne(t => t.Pet)
            .WithMany(p => p.TreatmentNotes)
            .HasForeignKey(t => t.PetId);

        builder.Entity<Appointment>()
            .HasOne(a => a.Pet)
            .WithMany(p => p.Appointments)
            .HasForeignKey(a => a.PetId);

        builder.Entity<Invoice>()
            .HasOne(i => i.Pet)
            .WithMany()
            .HasForeignKey(i => i.PetId);

        builder.Entity<Invoice>()
            .HasOne(i => i.Appointment)
            .WithMany()
            .HasForeignKey(i => i.AppointmentId);

        builder.Entity<InvoiceLineItem>()
            .HasOne(li => li.Invoice)
            .WithMany(i => i.LineItems)
            .HasForeignKey(li => li.InvoiceId);

        builder.Entity<Payment>()
            .HasOne(p => p.Invoice)
            .WithMany()
            .HasForeignKey(p => p.InvoiceId);

        builder.Entity<InvoiceLineItem>()
            .Property(li => li.Amount)
            .HasColumnType("decimal(18,2)");

        builder.Entity<Payment>()
            .Property(p => p.Amount)
            .HasColumnType("decimal(18,2)");

        builder.Entity<Pet>()
            .Property(p => p.Weight)
            .HasColumnType("decimal(18,2)");
    }
}
```

## 3. Update Program.cs

Edit `/tmp/sv-853694e2a8f1424186ac75de4d52b6b6/VetClinic/Program.cs`. After `builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();` add:

```csharp
builder.Services.AddAuthorization(options =>
{
    options.FallbackPolicy = options.DefaultPolicy;
});
```

Also change `options.SignIn.RequireConfirmedAccount = true;` to `options.SignIn.RequireConfirmedAccount = false;` so staff can log in immediately without email confirmation (intranet app).

## 4. Delete template pages

Delete these files:
- `/tmp/sv-853694e2a8f1424186ac75de4d52b6b6/VetClinic/Components/Pages/Counter.razor`
- `/tmp/sv-853694e2a8f1424186ac75de4d52b6b6/VetClinic/Components/Pages/Weather.razor`

## 5. Create Pages

### Home.razor - Replace existing with Dashboard

Replace `/tmp/sv-853694e2a8f1424186ac75de4d52b6b6/VetClinic/Components/Pages/Home.razor` with:

```razor
@page "/"
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1>Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-3">
        <div class="card text-bg-primary">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info">
            <div class="card-body">
                <h5 class="card-title">This Week</h5>
                <p class="card-text display-6">@weekAppointments</p>
            </div>
        </div>
    </div>
</div>

<div class="row">
    <div class="col-md-6">
        <h4>Upcoming Appointments</h4>
        @if (upcomingAppointments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Time</th><th>Pet</th><th>Reason</th><th>Vet</th></tr></thead>
                <tbody>
                    @foreach (var apt in upcomingAppointments)
                    {
                        <tr>
                            <td>@apt.StartTime.ToString("g")</td>
                            <td>@apt.Pet.Name</td>
                            <td>@apt.Reason</td>
                            <td>@apt.VeterinarianName</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No upcoming appointments.</p>
        }
    </div>
    <div class="col-md-6">
        <h4>Recent Payments</h4>
        @if (recentPayments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Pet</th></tr></thead>
                <tbody>
                    @foreach (var pay in recentPayments)
                    {
                        <tr>
                            <td>@pay.PaymentDate.ToString("d")</td>
                            <td>@pay.Amount.ToString("C")</td>
                            <td>@pay.Method</td>
                            <td>@pay.Invoice.Pet.Name</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No recent payments.</p>
        }
    </div>
</div>

@code {
    private int petCount;
    private int todayAppointments;
    private int pendingInvoices;
    private int weekAppointments;
    private List<Appointment> upcomingAppointments = new();
    private List<Payment> recentPayments = new();

    protected override async Task OnInitializedAsync()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var now = DateTime.Now;
        var today = now.Date;
        var weekEnd = today.AddDays(7);

        petCount = await db.Pets.CountAsync();
        todayAppointments = await db.Appointments
            .CountAsync(a => a.StartTime.Date == today && a.Status == AppointmentStatus.Scheduled);
        pendingInvoices = await db.Invoices
            .CountAsync(i => i.Status == InvoiceStatus.Issued || i.Status == InvoiceStatus.Overdue);
        weekAppointments = await db.Appointments
            .CountAsync(a => a.StartTime >= now && a.StartTime <= weekEnd && a.Status == AppointmentStatus.Scheduled);

        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= now && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToListAsync();

        recentPayments = await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet)
            .OrderByDescending(p => p.PaymentDate)
            .Take(5)
            .ToListAsync();
    }
}
```

### Patients.razor - Patient list and registration

Create `/tmp/sv-853694e2a8f1424186ac75de4d52b6b6/VetClinic/Components/Pages/Patients.razor`:

```razor
@page "/patients"
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Patients</PageTitle>

<h1>Patients</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by pet or owner name..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowRegisterForm">
            <i class="bi bi-plus-circle"></i> Register New Pet
        </button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-header">@(editingPet == null ? "Register New Pet" : "Edit Pet")</div>
        <div class="card-body">
            <EditForm Model="formModel" OnValidSubmit="SavePet" FormName="petForm">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />
