@code {
    private string activeTab = "invoices";
    private List<Invoice> invoices = new();
    private List<Payment> payments = new();
    private List<Pet> availablePets = new();
    private bool showInvoiceForm;
    private bool showPaymentForm;
    private Invoice? payingInvoice;
    private InvoiceFormModel invoiceModel = new();
    private PaymentFormModel paymentModel = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        invoices = await db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.LineItems)
            .OrderByDescending(i => i.IssuedDate)
            .ToListAsync();

        payments = await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet)
            .OrderByDescending(p => p.PaymentDate)
            .ToListAsync();

        availablePets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private void ShowInvoiceForm()
    {
        invoiceModel = new InvoiceFormModel
        {
            DueDate = DateTime.Today.AddDays(30)
        };
        invoiceModel.LineItems.Add(new LineItemModel());
        showInvoiceForm = true;
    }

    private void AddLineItem() => invoiceModel.LineItems.Add(new LineItemModel());

    private async Task SaveInvoice()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var invoice = new Invoice
        {
            PetId = invoiceModel.PetId,
            IssuedDate = DateTime.Now,
            DueDate = invoiceModel.DueDate,
            Status = InvoiceStatus.Draft,
            LineItems = invoiceModel.LineItems.Select(li => new InvoiceLineItem
            {
                Description = li.Description,
                Quantity = li.Quantity,
                Amount = li.Amount
            }).ToList()
        };
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadData();
    }

    private async Task IssueInvoice(Invoice inv)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var invoice = await db.Invoices.FindAsync(inv.Id);
        if (invoice != null) { invoice.Status = InvoiceStatus.Issued; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private async Task CancelInvoice(Invoice inv)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var invoice = await db.Invoices.FindAsync(inv.Id);
        if (invoice != null) { invoice.Status = InvoiceStatus.Cancelled; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private void ShowPaymentForm(Invoice inv)
    {
        payingInvoice = inv;
        paymentModel = new PaymentFormModel { Amount = inv.Total, Method = "Card" };
        showPaymentForm = true;
    }

    private async Task SavePayment()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var payment = new Payment
        {
            InvoiceId = payingInvoice!.Id,
            Amount = paymentModel.Amount,
            PaymentDate = DateTime.Now,
            Method = paymentModel.Method,
            Reference = paymentModel.Reference
        };
        db.Payments.Add(payment);

        var invoice = await db.Invoices.FindAsync(payingInvoice.Id);
        if (invoice != null) invoice.Status = InvoiceStatus.Paid;

        await db.SaveChangesAsync();
        showPaymentForm = false;
        await LoadData();
    }

    private string GetInvoiceBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Draft => "bg-secondary",
        InvoiceStatus.Issued => "bg-primary",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        InvoiceStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };

    private class InvoiceFormModel
    {
        public int PetId { get; set; }
        public DateTime DueDate { get; set; }
        public List<LineItemModel> LineItems { get; set; } = new();
    }

    private class LineItemModel
    {
        public string Description { get; set; } = string.Empty;
        public int Quantity { get; set; } = 1;
        public decimal Amount { get; set; }
    }

    private class PaymentFormModel
    {
        public decimal Amount { get; set; }
        public string Method { get; set; } = "Cash";
        public string? Reference { get; set; }
    }
}
