### Appointments.razor - Scheduling with availability view

Create `/tmp/sv-853694e2a8f1424186ac75de4d52b6b6/VetClinic/Components/Pages/Appointments.razor`:

```razor
@page "/appointments"
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Appointments</PageTitle>

<h1>Appointments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowCreateForm">New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-header">@(editingAppointment == null ? "Schedule Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="formModel" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-select" @bind-Value="formModel.PetId">
                            <option value="0">Select pet...</option>
                            @foreach (var pet in availablePets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.LastName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Start Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="formModel.StartTime" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Duration (minutes)</label>
                        <InputNumber class="form-control" @bind-Value="formModel.DurationMinutes" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Veterinarian</label>
