        var weekEnd = today.AddDays(7);

        petCount = await db.Pets.CountAsync();
        todayAppointments = await db.Appointments
            .CountAsync(a => a.StartTime.Date == today && a.Status == AppointmentStatus.Scheduled);
        pendingInvoices = await db.Invoices
            .CountAsync(i => i.Status == InvoiceStatus.Issued || i.Status == InvoiceStatus.Overdue);
        weekAppointments = await db.Appointments
            .CountAsync(a => a.StartTime >= now && a.StartTime <= weekEnd && a.Status == AppointmentStatus.Scheduled);

        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= now && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToListAsync();

        recentPayments = await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet)
            .OrderByDescending(p => p.PaymentDate)
            .Take(5)
            .ToListAsync();
    }
