        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowCreateForm">New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-header">@(editingAppointment == null ? "Schedule Appointment" : "Edit Appointment")</div>
        <div class="card-body">
