@page "/"
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1>Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-3">
        <div class="card text-bg-primary">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info">
            <div class="card-body">
                <h5 class="card-title">This Week</h5>
                <p class="card-text display-6">@weekAppointments</p>
            </div>
        </div>
    </div>
</div>

<div class="row">
    <div class="col-md-6">
        <h4>Upcoming Appointments</h4>
        @if (upcomingAppointments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Time</th><th>Pet</th><th>Reason</th><th>Vet</th></tr></thead>
                <tbody>
                    @foreach (var apt in upcomingAppointments)
                    {
                        <tr>
                            <td>@apt.StartTime.ToString("g")</td>
                            <td>@apt.Pet.Name</td>
                            <td>@apt.Reason</td>
                            <td>@apt.VeterinarianName</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No upcoming appointments.</p>
        }
    </div>
    <div class="col-md-6">
        <h4>Recent Payments</h4>
        @if (recentPayments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Pet</th></tr></thead>
                <tbody>
                    @foreach (var pay in recentPayments)
                    {
                        <tr>
                            <td>@pay.PaymentDate.ToString("d")</td>
                            <td>@pay.Amount.ToString("C")</td>
                            <td>@pay.Method</td>
                            <td>@pay.Invoice.Pet.Name</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No recent payments.</p>
        }
    </div>
</div>

@code {
    private int petCount;
    private int todayAppointments;
    private int pendingInvoices;
    private int weekAppointments;
    private List<Appointment> upcomingAppointments = new();
    private List<Payment> recentPayments = new();

    protected override async Task OnInitializedAsync()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var now = DateTime.Now;
        var today = now.Date;
        var weekEnd = today.AddDays(7);

        petCount = await db.Pets.CountAsync();
        todayAppointments = await db.Appointments
            .CountAsync(a => a.StartTime.Date == today && a.Status == AppointmentStatus.Scheduled);
        pendingInvoices = await db.Invoices
            .CountAsync(i => i.Status == InvoiceStatus.Issued || i.Status == InvoiceStatus.Overdue);
        weekAppointments = await db.Appointments
            .CountAsync(a => a.StartTime >= now && a.StartTime <= weekEnd && a.Status == AppointmentStatus.Scheduled);

        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= now && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToListAsync();

        recentPayments = await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet)
            .OrderByDescending(p => p.PaymentDate)
            .Take(5)
            .ToListAsync();
    }
}

