</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-header">@(editingPet == null ? "Register New Pet" : "Edit Pet")</div>
        <div class="card-body">
            <EditForm Model="formModel" OnValidSubmit="SavePet" FormName="petForm">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />
                <div class="row">
                    <div class="col-md-6">
                        <h5>Owner Information</h5>
