                        <td>@apt.Reason</td>
                        <td>@apt.VeterinarianName</td>
                        <td><span class="badge @GetBadgeClass(apt.Status)">@apt.Status</span></td>
                        <td>
                            @if (apt.Status == AppointmentStatus.Scheduled)
                            {
                                <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(apt)">Reschedule</button>
                                <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(apt)">Complete</button>
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(apt)">Cancel</button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">Available Time Slots</div>
            <div class="card-body">
                @foreach (var slot in availableSlots)
                {
                    <span class="badge bg-success me-1 mb-1 p-2">@slot</span>
                }
                @if (!availableSlots.Any())
                {
                    <p class="text-muted">No available slots.</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private DateOnly selectedDate = DateOnly.FromDateTime(DateTime.Today);
    private List<Appointment> appointments = new();
    private List<Pet> availablePets = new();
    private List<string> availableSlots = new();
    private bool showForm;
    private Appointment? editingAppointment;
    private AppointmentFormModel formModel = new();
    private string? conflictMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadAppointments();
        await LoadPets();
    }

    private async Task LoadPets()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        availablePets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private async Task LoadAppointments()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var date = selectedDate.ToDateTime(TimeOnly.MinValue);
        var nextDate = date.AddDays(1);

        appointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= date && a.StartTime < nextDate)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        CalculateAvailableSlots();
    }

    private void CalculateAvailableSlots()
    {
        availableSlots.Clear();
        var clinicStart = 8;
        var clinicEnd = 18;
        var slotDuration = 30;

        var scheduledSlots = appointments
            .Where(a => a.Status == AppointmentStatus.Scheduled)
            .ToList();

        for (int hour = clinicStart; hour < clinicEnd; hour++)
        {
            for (int min = 0; min < 60; min += slotDuration)
            {
                var slotStart = selectedDate.ToDateTime(new TimeOnly(hour, min));
                var slotEnd = slotStart.AddMinutes(slotDuration);

                bool isOccupied = scheduledSlots.Any(a => a.StartTime < slotEnd && a.EndTime > slotStart);
                if (!isOccupied)
                {
                    availableSlots.Add($"{hour:D2}:{min:D2}");
                }
            }
        }
    }

    private void ShowCreateForm()
    {
        editingAppointment = null;
        conflictMessage = null;
        formModel = new AppointmentFormModel
        {
            StartTime = selectedDate.ToDateTime(new TimeOnly(9, 0)),
            DurationMinutes = 30
        };
        showForm = true;
    }

    private void Reschedule(Appointment apt)
    {
        editingAppointment = apt;
        conflictMessage = null;
        formModel = new AppointmentFormModel
        {
            PetId = apt.PetId,
            StartTime = apt.StartTime,
            DurationMinutes = (int)(apt.EndTime - apt.StartTime).TotalMinutes,
            VeterinarianName = apt.VeterinarianName,
            Reason = apt.Reason,
            Notes = apt.Notes
        };
        showForm = true;
    }

    private async Task Complete(Appointment apt)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var a = await db.Appointments.FindAsync(apt.Id);
        if (a != null) { a.Status = AppointmentStatus.Completed; await db.SaveChangesAsync(); }
        await LoadAppointments();
    }

    private async Task Cancel(Appointment apt)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var a = await db.Appointments.FindAsync(apt.Id);
        if (a != null) { a.Status = AppointmentStatus.Cancelled; await db.SaveChangesAsync(); }
        await LoadAppointments();
    }

    private async Task SaveAppointment()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var endTime = formModel.StartTime.AddMinutes(formModel.DurationMinutes);

        var conflict = await db.Appointments
            .Where(a => a.Status == AppointmentStatus.Scheduled
                && a.StartTime < endTime && a.EndTime > formModel.StartTime
                && (editingAppointment == null || a.Id != editingAppointment.Id))
            .AnyAsync();

        if (conflict)
        {
            conflictMessage = "This time slot conflicts with an existing appointment.";
            return;
        }

        if (editingAppointment != null)
        {
            var apt = await db.Appointments.FindAsync(editingAppointment.Id);
            if (apt != null)
            {
                apt.PetId = formModel.PetId;
                apt.StartTime = formModel.StartTime;
                apt.EndTime = endTime;
                apt.Reason = formModel.Reason;
                apt.VeterinarianName = formModel.VeterinarianName;
                apt.Notes = formModel.Notes;
            }
        }
        else
        {
            db.Appointments.Add(new Appointment
            {
                PetId = formModel.PetId,
                StartTime = formModel.StartTime,
                EndTime = endTime,
                Reason = formModel.Reason,
                VeterinarianName = formModel.VeterinarianName,
                Notes = formModel.Notes,
                Status = AppointmentStatus.Scheduled
            });
        }

        await db.SaveChangesAsync();
        showForm = false;
        conflictMessage = null;
        await LoadAppointments();
    }

    private string GetRowClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Cancelled => "table-secondary text-decoration-line-through",
        AppointmentStatus.Completed => "table-success",
        _ => ""
    };

    private string GetBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        AppointmentStatus.NoShow => "bg-danger",
        _ => "bg-secondary"
    };

    private class AppointmentFormModel
    {
        public int PetId { get; set; }
        public DateTime StartTime { get; set; }
        public int DurationMinutes { get; set; } = 30;
        public string VeterinarianName { get; set; } = string.Empty;
        public string Reason { get; set; } = string.Empty;
        public string Notes { get; set; } = string.Empty;
    }
}

@page "/billing"
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Billing</PageTitle>

<h1>Billing</h1>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => activeTab = "payments"'>Payment History</button>
    </li>
</ul>

@if (activeTab == "invoices")
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowInvoiceForm">Create Invoice</button>
    </div>

    @if (showInvoiceForm)
    {
        <div class="card mb-4">
            <div class="card-header">New Invoice</div>
            <div class="card-body">
                <EditForm Model="invoiceModel" OnValidSubmit="SaveInvoice" FormName="invoiceForm">
                    <div class="row mb-3">
                        <div class="col-md-4">
                            <label class="form-label">Pet</label>
                            <InputSelect class="form-select" @bind-Value="invoiceModel.PetId">
                                <option value="0">Select pet...</option>
                                @foreach (var pet in availablePets)
                                {
                                    <option value="@pet.Id">@pet.Name (@pet.Owner.LastName)</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Due Date</label>
                            <InputDate class="form-control" @bind-Value="invoiceModel.DueDate" />
                        </div>
                    </div>

                    <h5>Line Items</h5>
                    @for (int i = 0; i < invoiceModel.LineItems.Count; i++)
                    {
                        var index = i;
                        <div class="row mb-2">
                            <div class="col-md-5">
                                <input class="form-control" placeholder="Description"
                                       @bind="invoiceModel.LineItems[index].Description" />
                            </div>
                            <div class="col-md-2">
                                <input type="number" class="form-control" placeholder="Qty"
                                       @bind="invoiceModel.LineItems[index].Quantity" />
                            </div>
                            <div class="col-md-3">
                                <input type="number" step="0.01" class="form-control" placeholder="Amount"
                                       @bind="invoiceModel.LineItems[index].Amount" />
                            </div>
                            <div class="col-md-2">
                                <button type="button" class="btn btn-outline-danger" @onclick="() => invoiceModel.LineItems.RemoveAt(index)">Remove</button>
                            </div>
                        </div>
                    }
                    <button type="button" class="btn btn-outline-secondary btn-sm mb-3" @onclick="AddLineItem">+ Add Line Item</button>

                    <div class="mb-2"><strong>Total: @invoiceModel.LineItems.Sum(li => li.Amount * li.Quantity).ToString("C")</strong></div>

                    <button type="submit" class="btn btn-success me-2">Create Invoice</button>
                    <button type="button" class="btn btn-secondary" @onclick="() => showInvoiceForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    <table class="table table-hover">
        <thead><tr><th>#</th><th>Date</th><th>Pet</th><th>Total</th><th>Status</th><th>Actions</th></tr></thead>
        <tbody>
            @foreach (var inv in invoices)
            {
                <tr>
                    <td>INV-@inv.Id.ToString("D4")</td>
                    <td>@inv.IssuedDate.ToString("d")</td>
                    <td>@inv.Pet.Name</td>
                    <td>@inv.Total.ToString("C")</td>
                    <td><span class="badge @GetInvoiceBadge(inv.Status)">@inv.Status</span></td>
                    <td>
                        @if (inv.Status == InvoiceStatus.Issued || inv.Status == InvoiceStatus.Overdue)
                        {
                            <button class="btn btn-sm btn-success" @onclick="() => ShowPaymentForm(inv)">Record Payment</button>
                        }
                        @if (inv.Status == InvoiceStatus.Draft)
                        {
                            <button class="btn btn-sm btn-primary" @onclick="() => IssueInvoice(inv)">Issue</button>
                            <button class="btn btn-sm btn-danger" @onclick="() => CancelInvoice(inv)">Cancel</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@if (activeTab == "payments")
{
    <table class="table table-hover">
        <thead><tr><th>Date</th><th>Invoice</th><th>Pet</th><th>Amount</th><th>Method</th><th>Reference</th></tr></thead>
        <tbody>
            @foreach (var pay in payments)
            {
                <tr>
                    <td>@pay.PaymentDate.ToString("d")</td>
                    <td>INV-@pay.InvoiceId.ToString("D4")</td>
                    <td>@pay.Invoice.Pet.Name</td>
                    <td>@pay.Amount.ToString("C")</td>
                    <td>@pay.Method</td>
                    <td>@pay.Reference</td>
                </tr>
            }
        </tbody>
    </table>
}

@if (showPaymentForm)
{
    <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Record Payment for INV-@payingInvoice!.Id.ToString("D4")</h5>
                    <button type="button" class="btn-close" @onclick="() => showPaymentForm = false"></button>
                </div>
                <div class="modal-body">
                    <EditForm Model="paymentModel" OnValidSubmit="SavePayment" FormName="paymentForm">
                        <div class="mb-2">
                            <label class="form-label">Amount</label>
                            <InputNumber class="form-control" @bind-Value="paymentModel.Amount" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Method</label>
                            <InputSelect class="form-select" @bind-Value="paymentModel.Method">
                                <option value="Cash">Cash</option>
                                <option value="Card">Card</option>
                                <option value="Check">Check</option>
                            </InputSelect>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Reference (optional)</label>
                            <InputText class="form-control" @bind-Value="paymentModel.Reference" />
                        </div>
                        <button type="submit" class="btn btn-success">Process Payment</button>
                    </EditForm>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string activeTab = "invoices";
    private List<Invoice> invoices = new();
    private List<Payment> payments = new();
    private List<Pet> availablePets = new();
    private bool showInvoiceForm;
    private bool showPaymentForm;
    private Invoice? payingInvoice;
    private InvoiceFormModel invoiceModel = new();
    private PaymentFormModel paymentModel = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        invoices = await db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.LineItems)
            .OrderByDescending(i => i.IssuedDate)
            .ToListAsync();

        payments = await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet)
            .OrderByDescending(p => p.PaymentDate)
            .ToListAsync();

        availablePets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private void ShowInvoiceForm()
    {
        invoiceModel = new InvoiceFormModel
        {
            DueDate = DateTime.Today.AddDays(30)
        };
        invoiceModel.LineItems.Add(new LineItemModel());
        showInvoiceForm = true;
    }

    private void AddLineItem() => invoiceModel.LineItems.Add(new LineItemModel());

    private async Task SaveInvoice()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var invoice = new Invoice
        {
            PetId = invoiceModel.PetId,
            IssuedDate = DateTime.Now,
            DueDate = invoiceModel.DueDate,
            Status = InvoiceStatus.Draft,
            LineItems = invoiceModel.LineItems.Select(li => new InvoiceLineItem
            {
                Description = li.Description,
                Quantity = li.Quantity,
                Amount = li.Amount
            }).ToList()
        };
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadData();
    }

    private async Task IssueInvoice(Invoice inv)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var invoice = await db.Invoices.FindAsync(inv.Id);
        if (invoice != null) { invoice.Status = InvoiceStatus.Issued; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private async Task CancelInvoice(Invoice inv)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var invoice = await db.Invoices.FindAsync(inv.Id);
        if (invoice != null) { invoice.Status = InvoiceStatus.Cancelled; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private void ShowPaymentForm(Invoice inv)
    {
        payingInvoice = inv;
        paymentModel = new PaymentFormModel { Amount = inv.Total, Method = "Card" };
        showPaymentForm = true;
    }

    private async Task SavePayment()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var payment = new Payment
        {
            InvoiceId = payingInvoice!.Id,
            Amount = paymentModel.Amount,
            PaymentDate = DateTime.Now,
            Method = paymentModel.Method,
            Reference = paymentModel.Reference
        };
        db.Payments.Add(payment);

        var invoice = await db.Invoices.FindAsync(payingInvoice.Id);
        if (invoice != null) invoice.Status = InvoiceStatus.Paid;

        await db.SaveChangesAsync();
        showPaymentForm = false;
        await LoadData();
    }

    private string GetInvoiceBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Draft => "bg-secondary",
        InvoiceStatus.Issued => "bg-primary",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        InvoiceStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };

    private class InvoiceFormModel
    {
        public int PetId { get; set; }
        public DateTime DueDate { get; set; }
        public List<LineItemModel> LineItems { get; set; } = new();
    }

    private class LineItemModel
    {
        public string Description { get; set; } = string.Empty;
        public int Quantity { get; set; } = 1;
        public decimal Amount { get; set; }
    }

    private class PaymentFormModel
    {
        public decimal Amount { get; set; }
        public string Method { get; set; } = "Cash";
        public string? Reference { get; set; }
    }
}

