        <h4>Upcoming Appointments</h4>
        @if (upcomingAppointments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Time</th><th>Pet</th><th>Reason</th><th>Vet</th></tr></thead>
                <tbody>
                    @foreach (var apt in upcomingAppointments)
