@code {
    private List<Pet> pets = new();
    private string searchTerm = string.Empty;
    private bool showForm;
    private Pet? editingPet;
    private PetFormModel formModel = new();

    protected override async Task OnInitializedAsync() => await LoadPets();

    private async Task LoadPets()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private async Task Search()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        if (string.IsNullOrWhiteSpace(searchTerm))
        {
            pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        }
        else
        {
            var term = searchTerm.ToLower();
            pets = await db.Pets.Include(p => p.Owner)
                .Where(p => p.Name.ToLower().Contains(term)
                    || p.Owner.FirstName.ToLower().Contains(term)
                    || p.Owner.LastName.ToLower().Contains(term))
                .OrderBy(p => p.Name)
                .ToListAsync();
        }
    }

    private void ShowRegisterForm()
    {
        editingPet = null;
        formModel = new PetFormModel { DateOfBirth = DateOnly.FromDateTime(DateTime.Today) };
        showForm = true;
    }

    private void EditPet(Pet pet)
    {
        editingPet = pet;
        formModel = new PetFormModel
        {
            PetName = pet.Name,
            Species = pet.Species,
            Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth,
            Weight = pet.Weight,
            OwnerFirstName = pet.Owner.FirstName,
            OwnerLastName = pet.Owner.LastName,
            OwnerPhone = pet.Owner.Phone,
            OwnerEmail = pet.Owner.Email
        };
        showForm = true;
    }

    private void CancelForm() => showForm = false;

    private async Task SavePet()
    {
        await using var db = await DbFactory.CreateDbContextAsync();

        if (editingPet != null)
        {
            var pet = await db.Pets.Include(p => p.Owner).FirstAsync(p => p.Id == editingPet.Id);
            pet.Name = formModel.PetName;
            pet.Species = formModel.Species;
            pet.Breed = formModel.Breed;
            pet.DateOfBirth = formModel.DateOfBirth;
            pet.Weight = formModel.Weight;
            pet.Owner.FirstName = formModel.OwnerFirstName;
            pet.Owner.LastName = formModel.OwnerLastName;
            pet.Owner.Phone = formModel.OwnerPhone;
            pet.Owner.Email = formModel.OwnerEmail;
        }
        else
        {
            var owner = new Owner
            {
                FirstName = formModel.OwnerFirstName,
                LastName = formModel.OwnerLastName,
                Phone = formModel.OwnerPhone,
                Email = formModel.OwnerEmail
            };
            var pet = new Pet
            {
                Name = formModel.PetName,
                Species = formModel.Species,
                Breed = formModel.Breed,
                DateOfBirth = formModel.DateOfBirth,
                Weight = formModel.Weight,
                Owner = owner
            };
            db.Pets.Add(pet);
        }

        await db.SaveChangesAsync();
        showForm = false;
        await LoadPets();
    }

    private class PetFormModel
    {
        public string PetName { get; set; } = string.Empty;
        public string Species { get; set; } = string.Empty;
        public string Breed { get; set; } = string.Empty;
        public DateOnly DateOfBirth { get; set; }
        public decimal Weight { get; set; }
        public string OwnerFirstName { get; set; } = string.Empty;
        public string OwnerLastName { get; set; } = string.Empty;
        public string OwnerPhone { get; set; } = string.Empty;
        public string OwnerEmail { get; set; } = string.Empty;
    }
}

