            <div class="card-body">
                @foreach (var slot in availableSlots)
                {
                    <span class="badge bg-success me-1 mb-1 p-2">@slot</span>
                }
                @if (!availableSlots.Any())
                {
                    <p class="text-muted">No available slots.</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private DateOnly selectedDate = DateOnly.FromDateTime(DateTime.Today);
    private List<Appointment> appointments = new();
    private List<Pet> availablePets = new();
    private List<string> availableSlots = new();
    private bool showForm;
    private Appointment? editingAppointment;
    private AppointmentFormModel formModel = new();
    private string? conflictMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadAppointments();
        await LoadPets();
    }

    private async Task LoadPets()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        availablePets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private async Task LoadAppointments()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var date = selectedDate.ToDateTime(TimeOnly.MinValue);
        var nextDate = date.AddDays(1);

        appointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= date && a.StartTime < nextDate)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        CalculateAvailableSlots();
    }

    private void CalculateAvailableSlots()
    {
        availableSlots.Clear();
        var clinicStart = 8;
        var clinicEnd = 18;
        var slotDuration = 30;

        var scheduledSlots = appointments
            .Where(a => a.Status == AppointmentStatus.Scheduled)
            .ToList();

        for (int hour = clinicStart; hour < clinicEnd; hour++)
        {
            for (int min = 0; min < 60; min += slotDuration)
            {
                var slotStart = selectedDate.ToDateTime(new TimeOnly(hour, min));
                var slotEnd = slotStart.AddMinutes(slotDuration);

                bool isOccupied = scheduledSlots.Any(a => a.StartTime < slotEnd && a.EndTime > slotStart);
                if (!isOccupied)
                {
                    availableSlots.Add($"{hour:D2}:{min:D2}");
                }
            }
        }
    }

    private void ShowCreateForm()
    {
        editingAppointment = null;
        conflictMessage = null;
        formModel = new AppointmentFormModel
        {
            StartTime = selectedDate.ToDateTime(new TimeOnly(9, 0)),
            DurationMinutes = 30
        };
        showForm = true;
    }

    private void Reschedule(Appointment apt)
    {
        editingAppointment = apt;
        conflictMessage = null;
        formModel = new AppointmentFormModel
        {
            PetId = apt.PetId,
            StartTime = apt.StartTime,
            DurationMinutes = (int)(apt.EndTime - apt.StartTime).TotalMinutes,
            VeterinarianName = apt.VeterinarianName,
            Reason = apt.Reason,
            Notes = apt.Notes
        };
        showForm = true;
    }

    private async Task Complete(Appointment apt)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var a = await db.Appointments.FindAsync(apt.Id);
        if (a != null) { a.Status = AppointmentStatus.Completed; await db.SaveChangesAsync(); }
        await LoadAppointments();
    }

    private async Task Cancel(Appointment apt)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var a = await db.Appointments.FindAsync(apt.Id);
        if (a != null) { a.Status = AppointmentStatus.Cancelled; await db.SaveChangesAsync(); }
        await LoadAppointments();
    }

    private async Task SaveAppointment()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var endTime = formModel.StartTime.AddMinutes(formModel.DurationMinutes);

        var conflict = await db.Appointments
            .Where(a => a.Status == AppointmentStatus.Scheduled
                && a.StartTime < endTime && a.EndTime > formModel.StartTime
                && (editingAppointment == null || a.Id != editingAppointment.Id))
            .AnyAsync();

        if (conflict)
        {
            conflictMessage = "This time slot conflicts with an existing appointment.";
            return;
        }

        if (editingAppointment != null)
        {
            var apt = await db.Appointments.FindAsync(editingAppointment.Id);
            if (apt != null)
            {
                apt.PetId = formModel.PetId;
                apt.StartTime = formModel.StartTime;
                apt.EndTime = endTime;
                apt.Reason = formModel.Reason;
                apt.VeterinarianName = formModel.VeterinarianName;
                apt.Notes = formModel.Notes;
            }
        }
        else
        {
            db.Appointments.Add(new Appointment
            {
                PetId = formModel.PetId,
                StartTime = formModel.StartTime,
                EndTime = endTime,
                Reason = formModel.Reason,
                VeterinarianName = formModel.VeterinarianName,
                Notes = formModel.Notes,
                Status = AppointmentStatus.Scheduled
            });
        }

        await db.SaveChangesAsync();
        showForm = false;
        conflictMessage = null;
        await LoadAppointments();
    }

    private string GetRowClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Cancelled => "table-secondary text-decoration-line-through",
        AppointmentStatus.Completed => "table-success",
        _ => ""
    };

    private string GetBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        AppointmentStatus.NoShow => "bg-danger",
        _ => "bg-secondary"
    };

    private class AppointmentFormModel
    {
        public int PetId { get; set; }
        public DateTime StartTime { get; set; }
        public int DurationMinutes { get; set; } = 30;
        public string VeterinarianName { get; set; } = string.Empty;
        public string Reason { get; set; } = string.Empty;
        public string Notes { get; set; } = string.Empty;
    }
}

